import base64
import xml.etree.ElementTree as ET

class SAMLValidationError(Exception):
    pass

NS = {
    "samlp": "urn:oasis:names:tc:SAML:2.0:protocol",
    "saml": "urn:oasis:names:tc:SAML:2.0:assertion",
    "ds": "http://www.w3.org/2000/09/xmldsig#",
}

def decode_saml_response(encoded_response: str) -> str:
    if not encoded_response:
        raise SAMLValidationError("Missing SAMLResponse")
    try:
        decoded = base64.b64decode(encoded_response)
        return decoded.decode("utf-8")
    except Exception as exc:
        raise SAMLValidationError("Invalid base64 SAMLResponse") from exc

def parse_saml_response(xml_string: str) -> dict:
    try:
        root = ET.fromstring(xml_string)
    except ET.ParseError as exc:
        raise SAMLValidationError("Malformed XML") from exc

    if root.tag != f"{{{NS['samlp']}}}Response":
        raise SAMLValidationError("Root element must be samlp:Response")

    assertion = root.find("saml:Assertion", NS)
    if assertion is None:
        encrypted_assertion = root.find("saml:EncryptedAssertion", NS)
        if encrypted_assertion is not None:
            raise SAMLValidationError("EncryptedAssertion is not supported")
        raise SAMLValidationError("Missing saml:Assertion")

    subject = assertion.find("saml:Subject", NS)
    if subject is None:
        raise SAMLValidationError("Missing saml:Subject")

    name_id_elem = subject.find("saml:NameID", NS)
    if name_id_elem is None or not (name_id_elem.text and name_id_elem.text.strip()):
        raise SAMLValidationError("Missing saml:NameID")

    conditions = assertion.find("saml:Conditions", NS)
    if conditions is None:
        raise SAMLValidationError("Missing saml:Conditions")

    attr_statement = assertion.find("saml:AttributeStatement", NS)
    attributes = {}
    if attr_statement is not None:
        for attr in attr_statement.findall("saml:Attribute", NS):
            name = attr.attrib.get("Name") or attr.attrib.get("FriendlyName")
            if not name:
                continue
            values = []
            for val in attr.findall("saml:AttributeValue", NS):
                if val.text is not None:
                    values.append(val.text.strip())
            attributes[name] = values

    issuer_elem = root.find("saml:Issuer", NS)
    issuer = issuer_elem.text.strip() if issuer_elem is not None and issuer_elem.text else None

    status_code = root.find("samlp:Status/samlp:StatusCode", NS)
    if status_code is None:
        raise SAMLValidationError("Missing StatusCode")
    if status_code.attrib.get("Value") != "urn:oasis:names:tc:SAML:2.0:status:Success":
        raise SAMLValidationError("SAML response status is not Success")

    return {
        "issuer": issuer,
        "name_id": name_id_elem.text.strip(),
        "attributes": attributes,
    }

def map_user_fields(attributes: dict, attribute_map: dict) -> dict:
    mapped = {}
    for field, candidates in attribute_map.items():
        for candidate in candidates:
            if candidate in attributes and attributes[candidate]:
                mapped[field] = attributes[candidate][0]
                break
    return mapped

# saml_sp/views.py
from django.conf import settings
from django.contrib import messages
from django.contrib.auth import get_user_model, login, logout
from django.contrib.auth.models import User
from django.http import HttpResponse, HttpResponseBadRequest
from django.shortcuts import redirect
from django.views.decorators.csrf import csrf_exempt
from .saml import decode_saml_response, parse_saml_response, map_user_fields, SAMLValidationError

UserModel = get_user_model()

def _get_or_create_user(name_id: str, user_fields: dict):
    username = user_fields.get("username") or name_id
    defaults = {
        "email": user_fields.get("email", ""),
        "first_name": user_fields.get("first_name", ""),
        "last_name": user_fields.get("last_name", ""),
    }

    user, created = UserModel.objects.get_or_create(username=username, defaults=defaults)
    updated = False

    for field, value in defaults.items():
        if value and getattr(user, field, "") != value:
            setattr(user, field, value)
            updated = True

    if not user.is_active:
        user.is_active = True
        updated = True

    if created:
        user.set_unusable_password()
        updated = True

    if updated:
        user.save()

    return user

@csrf_exempt
def acs_view(request):
    if request.method != "POST":
        return HttpResponseBadRequest("Only POST is allowed")

    saml_response = request.POST.get("SAMLResponse")
    relay_state = request.POST.get("RelayState")

    try:
        xml_string = decode_saml_response(saml_response)
        parsed = parse_saml_response(xml_string)
        user_fields = map_user_fields(
            parsed["attributes"],
            settings.SAML_SP.get("ATTRIBUTE_MAP", {}),
        )
        user = _get_or_create_user(parsed["name_id"], user_fields)
        login(request, user, backend="django.contrib.auth.backends.ModelBackend")

        request.session[settings.SAML_SP.get("SESSION_NAME_ID_KEY", "saml_name_id")] = parsed["name_id"]
        request.session[settings.SAML_SP.get("SESSION_ATTRIBUTES_KEY", "saml_attributes")] = parsed["attributes"]
        request.session["saml_issuer"] = parsed.get("issuer")

        if relay_state:
            return redirect(relay_state)
        return redirect(settings.LOGIN_REDIRECT_URL)
    except SAMLValidationError as exc:
        return HttpResponseBadRequest(f"SAML validation error: {exc}")

def home_view(request):
    if request.user.is_authenticated:
        attrs = request.session.get(settings.SAML_SP.get("SESSION_ATTRIBUTES_KEY", "saml_attributes"), {})
        name_id = request.session.get(settings.SAML_SP.get("SESSION_NAME_ID_KEY", "saml_name_id"), "")
        lines = [
            f"Authenticated user: {request.user.username}",
            f"NameID: {name_id}",
            f"Attributes: {attrs}",
        ]
        return HttpResponse("<br>".join(lines))
    return HttpResponse("Not authenticated")

def logout_view(request):
    logout(request)
    messages.success(request, "Logged out")
    return redirect("/")